.darma-loader-darma-research-blob-family-bounce { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #fb7185); --accent-2: var(--loader-secondary-color, #8b5cf6); width: calc(var(--loader-size, 84px) * 1.35); height: calc(var(--loader-size, 84px) * .65); display: flex; align-items: end; justify-content: center; gap: 7%; }
.darma-loader-darma-research-blob-family-bounce span { width: 19%; aspect-ratio: 1; border-radius: 58% 42% 55% 45% / 45% 55% 45% 55%; background: linear-gradient(135deg, var(--accent), var(--accent-2)); box-shadow: inset 0 -8px #0002, 0 8px 18px color-mix(in srgb, var(--accent) 40%, transparent); animation: darma-loader-darma-research-blob-family-bounce-blob-bounce calc(var(--speed) * 1.15) cubic-bezier(.5,0,.2,1) infinite; }
.darma-loader-darma-research-blob-family-bounce span:nth-child(2) { animation-delay: .1s; width: 23%; } .darma-loader-darma-research-blob-family-bounce span:nth-child(3) { animation-delay: .2s; } .darma-loader-darma-research-blob-family-bounce span:nth-child(4) { animation-delay: .3s; width: 15%; }
@keyframes darma-loader-darma-research-blob-family-bounce-blob-bounce { 0%,100% { transform: translateY(0) scale(1.15,.85); } 45% { transform: translateY(-26px) scale(.82,1.18) rotate(12deg); border-radius: 42% 58% 45% 55% / 55% 45% 55% 45%; } 70% { transform: translateY(4px) scale(1.22,.78); } }

